                            id
                            name
                            imageUrl
                        }
                        post {
                            id
                            content
                        }
                    }
                    ... on ShareNotification {
                        post {
                            id
                            content
                        }
                    }
                }
            }
            pageInfo {
                hasNextPage
                endCursor
            }
        }
    }
}

