fun HackersPubApp(
    deepLinkData: pub.hackers.android.DeepLinkData? = null,
    navigationIntent: pub.hackers.android.NavigationIntent? = null,
    onDeepLinkConsumed: () -> Unit = {},
    onNavigationIntentConsumed: () -> Unit = {},
    viewModel: AppViewModel = hiltViewModel()
